mapper.insert:
/* termsSendMgmtMapper.insertTermsLmsSendTrgt */ INSERT INTO CMN_TERMS_SMS_SEND_MST ( SEQ_NUM , TRGT_YM , TYPE_CD , CONTRACT_NUM , MOBILE_NO , NAME , EMAIL , SUB_STAT , OPEN_DT , TMNT_DT , USER_ID , RESULT_YN , REGST_ID , REGST_DTTM , RVISN_ID , RVISN_DTTM ) SELECT TO_CHAR(SYSDATE,'YYMM') || SQ_MAIL_TERM_SEND.NEXTVAL , TO_CHAR(SYSDATE, 'YYYYMMDD') AS TRGT_YM , TYPE_CD , CONTRCT_NUM , CTN , NAME , EMAIL , SUB_STATUS , OPEN_DT , TMNT_DT , USER_ID , 'N' AS RESULT_YN , '운영팀' AS REGST_ID , SYSDATE AS REGST_DTTM , '운영팀' AS RVISN_ID , SYSDATE AS RVISN_DTTM FROM ( SELECT 'JG' AS TYPE_CD , A.CONTRACT_NUM AS CONTRCT_NUM , A.SUBSCRIBER_NO AS CTN , A.SUB_LINK_NAME AS NAME , '' AS EMAIL , A.SUB_STATUS , A.LST_COM_ACTV_DATE AS OPEN_DT , DECODE(A.SUB_STATUS, 'C' , SUBSTR(A.SUB_STATUS_DATE, 1 , 8), '') AS TMNT_DT , '' AS USER_ID FROM MSP_JUO_SUB_INFO A WHERE 1=1 AND A.SUB_STATUS <> 'C' AND A.LST_COM_ACTV_DATE = TO_CHAR(SYSDATE-337, 'YYYYMMDD')
UNION ALL
SELECT 'WEB' AS TYPE_CD , '' AS CONTRCT_NUM , A.MOBILE_NO AS CTN , A.NAME , A.EMAIL , A.STATUS AS SUB_STATUS , TO_CHAR(A.SYS_RDATE,'YYYYMMDD') AS OPEN_DT , '' AS TMNT_DT , A.USERID AS USER_ID FROM MCP_USER@DL_MCP A WHERE 1=1 AND A.MOBILE_NO IS NOT NULL AND A.USER_DIVISION = '00' AND LENGTH(A.MOBILE_NO) = '11' AND A.MOBILE_NO <> '01000000000' AND TO_CHAR(A.SYS_RDATE,'YYYYMMDD') = TO_CHAR(SYSDATE-337, 'YYYYMMDD') )

/* termsSendMgmtMapper.insertTermsLmsSendTrgt2 */ INSERT INTO CMN_TERMS_SMS_SEND_MST ( SEQ_NUM , TRGT_YM , TYPE_CD , CONTRACT_NUM , MOBILE_NO , NAME , EMAIL , SUB_STAT , OPEN_DT , TMNT_DT , USER_ID , RESULT_YN , REGST_ID , REGST_DTTM , RVISN_ID , RVISN_DTTM ) SELECT TO_CHAR(SYSDATE,'YYMM') || SQ_MAIL_TERM_SEND.NEXTVAL , TO_CHAR(SYSDATE, 'YYYYMMDD') AS TRGT_YM , TYPE_CD , CONTRCT_NUM , CTN , NAME , EMAIL , SUB_STATUS , OPEN_DT , TMNT_DT , USER_ID , 'N' AS RESULT_YN , '운영팀' AS REGST_ID , SYSDATE AS REGST_DTTM , '운영팀' AS RVISN_ID , SYSDATE AS RVISN_DTTM FROM ( SELECT 'JG' AS TYPE_CD , A.CONTRACT_NUM AS CONTRCT_NUM , A.SUBSCRIBER_NO AS CTN , A.SUB_LINK_NAME AS NAME , '' AS EMAIL , A.SUB_STATUS , A.LST_COM_ACTV_DATE AS OPEN_DT , DECODE(A.SUB_STATUS, 'C' , SUBSTR(A.SUB_STATUS_DATE, 1 , 8), '') AS TMNT_DT , '' AS USER_ID FROM MSP_JUO_SUB_INFO A WHERE 1=1 AND A.SUB_STATUS <> 'C' AND SUBSTR(A.LST_COM_ACTV_DATE,5,8) = TO_CHAR(SYSDATE-337, 'MMDD') AND SUBSTR(A.LST_COM_ACTV_DATE,1,4) <> TO_CHAR(SYSDATE,'YYYY')
UNION ALL
SELECT 'WEB' AS TYPE_CD , '' AS CONTRCT_NUM , A.MOBILE_NO AS CTN , A.NAME , A.EMAIL , A.STATUS AS SUB_STATUS , TO_CHAR(A.SYS_RDATE,'YYYYMMDD') AS OPEN_DT , '' AS TMNT_DT , A.USERID AS USER_ID FROM MCP_USER@DL_MCP A WHERE 1=1 AND A.MOBILE_NO IS NOT NULL AND A.USER_DIVISION = '00' AND LENGTH(A.MOBILE_NO) = '11' AND A.MOBILE_NO <> '01000000000' AND TO_CHAR(A.SYS_RDATE,'MMDD') = TO_CHAR(SYSDATE-337, 'MMDD') AND TO_CHAR(A.SYS_RDATE,'YYYY') <> TO_CHAR(SYSDATE,'YYYY') )

mapper.update:
UPDATE CMN_TERMS_SMS_SEND_MST
   SET MSEQ = #{mseq} 
       , RVISN_ID = 'BATCH'
       , RVISN_DTTM = SYSDATE
 WHERE SEQ_NUM = #{seqNum}

